INSERT INTO `glpi_notificationtemplatetranslations` VALUES (1,1,'','##lang.dbconnection.title##','##lang.dbconnection.delay## : ##dbconnection.delay##','<p>##lang.dbconnection.delay## : ##dbconnection.delay##</p>'),(2,2,'','##reservation.action##','======================================================================\n##lang.reservation.user##: ##reservation.user##\n##lang.reservation.item.name##: ##reservation.itemtype## - ##reservation.item.name##\n##IFreservation.tech## ##lang.reservation.tech## ##reservation.tech## ##ENDIFreservation.tech##\n##lang.reservation.begin##: ##reservation.begin##\n##lang.reservation.end##: ##reservation.end##\n##lang.reservation.comment##: ##reservation.comment##\n======================================================================','<!-- description{ color: inherit; background: #ebebeb;border-style: solid;border-color: #8d8d8d; border-width: 0px 1px 1px 0px; } -->\n<p><span style=\"color: #8b8c8f; font-weight: bold; text-decoration: underline;\">##lang.reservation.user##:</span>##reservation.user##<br /> <span style=\"color: #8b8c8f; font-weight: bold; text-decoration: underline;\">##lang.reservation.item.name##:</span>##reservation.itemtype## - ##reservation.item.name##<br />##IFreservation.tech## ##lang.reservation.tech## ##reservation.tech####ENDIFreservation.tech##<br /> <span style=\"color: #8b8c8f; font-weight: bold; text-decoration: underline;\">##lang.reservation.begin##:</span> ##reservation.begin##<br /> <span style=\"color: #8b8c8f; font-weight: bold; text-decoration: underline;\">##lang.reservation.end##:</span>##reservation.end##<br /> <span style=\"color: #8b8c8f; font-weight: bold; text-decoration: underline;\">##lang.reservation.comment##:</span> ##reservation.comment##</p>'),(3,3,'','##reservation.action##  ##reservation.entity##','##lang.reservation.entity## : ##reservation.entity##\n\n\n##FOREACHreservations##\n##lang.reservation.itemtype## : ##reservation.itemtype##\n\n ##lang.reservation.item## : ##reservation.item##\n\n ##reservation.url##\n\n ##ENDFOREACHreservations##','<p>##lang.reservation.entity## : ##reservation.entity## <br /> <br />\n##FOREACHreservations## <br />##lang.reservation.itemtype## :  ##reservation.itemtype##<br />\n ##lang.reservation.item## :  ##reservation.item##<br /> <br />\n <a href=\"##reservation.url##\"> ##reservation.url##</a><br />\n ##ENDFOREACHreservations##</p>'),(4,4,'es_CO','##ticket.action## ##ticket.title##','=-=-=-= Para responder por correo electrÔö£├óÔö¼Ôöénico, escriba arriba de esta lÔö£├óÔö¼┬ínea =-=-=-=\r\n\r\n##ticket.action##\r\n\r\nCaso NÔö£├®Ôö¼Ôûæ ##ticket.id## - ##ticket.title##\r\n\r\n------------------------------------------------------------\r\nUSUARIO SOLICITANTE\r\n------------------------------------------------------------\r\n##IFticket.authors## ##ticket.authors## ##ENDIFticket.authors####ELSEticket.authors##--##ENDELSEticket.authors##\r\n##IFticket.user.email## ##ticket.user.email## ##ENDIFticket.user.email##\r\n\r\nURL: ##ticket.url##\r\n\r\n------------------------------------------------------------\r\nDATOS DEL CASO\r\n------------------------------------------------------------\r\n##lang.ticket.creationdate##: ##ticket.creationdate##\r\n##lang.ticket.status##: ##ticket.status##\r\n##lang.ticket.requesttype##: ##ticket.requesttype##\r\n##lang.ticket.priority##: ##ticket.priority##\r\n##lang.ticket.urgency##: ##ticket.urgency##\r\n##IFticket.category####lang.ticket.category##: ##ticket.category####ENDIFticket.category##\r\n##IFticket.assigntousers####lang.ticket.assigntousers##: ##ticket.assigntousers####ENDIFticket.assigntousers##\r\n##IFticket.assigntogroups####lang.ticket.assigntogroups##: ##ticket.assigntogroups####ENDIFticket.assigntogroups##\r\n\r\n------------------------------------------------------------\r\n##lang.ticket.description##\r\n------------------------------------------------------------\r\n##ticket.content##\r\n\r\n##FOREACHitems##\r\n##IFticket.itemtype##\r\nEquipo: ##ticket.itemtype## - ##ticket.item.name##\r\n##IFticket.item.serial##  Serie: ##ticket.item.serial####ENDIFticket.item.serial##\r\n##IFticket.item.otherserial##  Inventario: ##ticket.item.otherserial####ENDIFticket.item.otherserial##\r\n##ENDIFticket.itemtype##\r\n##ENDFOREACHitems##\r\n\r\n##IFticket.storestatus=5##\r\n------------------------------------------------------------\r\nSOLUCIÔö£├ó├ö├ç┬úN\r\n------------------------------------------------------------\r\n##lang.ticket.solvedate##: ##ticket.solvedate##\r\n##lang.ticket.solution.type##: ##ticket.solution.type##\r\n##lang.ticket.solution.description##: ##ticket.solution.description##\r\n##ENDIFticket.storestatus##\r\n\r\n##FOREACHtimelineitems##\r\n[##timelineitems.date##] ##timelineitems.author## (##timelineitems.typename##)\r\n##timelineitems.description##\r\n\r\n##ENDFOREACHtimelineitems##\r\n\r\n##lang.ticket.numberoffollowups##: ##ticket.numberoffollowups##\r\n##lang.ticket.numberoftasks##: ##ticket.numberoftasks##\r\n\r\n------------------------------------------------------------\r\nÔö£├®Ôö¼ÔöÉCÔö£├óÔö¼Ôöémo crear un caso por correo?\r\nEnvÔö£├óÔö¼┬íe su correo a tisantacruz48@gmail.com con asunto claro,\r\nsu nombre completo, Ôö£├óÔö¼├¡rea/sede y descripciÔö£├óÔö¼Ôöén del problema.\r\n------------------------------------------------------------\r\nMesa de Ayuda TI - Grupo Empresarial Santacruz','<table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background:#f4f6f8;font-family:Arial,Helvetica,sans-serif;\">\r\n  <tr><td align=\"center\" style=\"padding:20px 10px;\">\r\n    <table role=\"presentation\" width=\"640\" cellpadding=\"0\" cellspacing=\"0\" style=\"max-width:640px;background:#ffffff;border:1px solid #e0e0e0;border-radius:6px;overflow:hidden;\">\r\n      <!-- Header -->\r\n      <tr><td style=\"background:#2E7D32;padding:20px 24px;\" align=\"center\">\r\n        <img src=\"https://helpdesk.grupo-santacruz.com/pics/logos/logo-GLPI-250-white.png\" alt=\"Grupo Santacruz\" height=\"60\" style=\"display:block;border:0;outline:none;height:60px;width:auto;\" />\r\n      </td></tr>\r\n\r\n      <!-- Action title -->\r\n      <tr><td style=\"background:#1B5E20;padding:12px 24px;color:#ffffff;font-size:16px;font-weight:bold;letter-spacing:.5px;\">\r\n        ##ticket.action##\r\n      </td></tr>\r\n\r\n      <!-- Greeting + ticket # -->\r\n      <tr><td style=\"padding:24px 24px 8px 24px;color:#212121;font-size:15px;\">\r\n        <p style=\"margin:0 0 12px 0;\">Mesa de Ayuda &mdash; Grupo Empresarial Santacruz</p>\r\n        <p style=\"margin:0;font-size:18px;color:#2E7D32;font-weight:bold;\">Caso N&deg; ##ticket.id## &mdash; ##ticket.title##</p>\r\n      </td></tr>\r\n\r\n      <!-- Requester block -->\r\n      <tr><td style=\"padding:8px 24px 16px 24px;\">\r\n        <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background:#f1f8f3;border-left:4px solid #2E7D32;border-radius:4px;\">\r\n          <tr><td style=\"padding:14px 16px;color:#212121;font-size:14px;\">\r\n            <div style=\"font-size:11px;color:#616161;text-transform:uppercase;letter-spacing:1px;margin-bottom:4px;\">Usuario solicitante</div>\r\n            <div style=\"font-size:16px;font-weight:bold;color:#1B5E20;\">\r\n              ##IFticket.authors## ##ticket.authors## ##ENDIFticket.authors##\r\n              ##ELSEticket.authors## -- ##ENDELSEticket.authors##\r\n            </div>\r\n            ##IFticket.user.email##\r\n            <div style=\"font-size:13px;color:#424242;margin-top:2px;\">##ticket.user.email##</div>\r\n            ##ENDIFticket.user.email##\r\n          </td></tr>\r\n        </table>\r\n      </td></tr>\r\n\r\n      <!-- Action button -->\r\n      <tr><td align=\"center\" style=\"padding:8px 24px 20px 24px;\">\r\n        <a href=\"##ticket.url##\" style=\"background:#2E7D32;color:#ffffff;text-decoration:none;padding:12px 28px;border-radius:4px;font-weight:bold;font-size:14px;display:inline-block;\">Abrir el caso en GLPI</a>\r\n      </td></tr>\r\n\r\n      <!-- Ticket details table -->\r\n      <tr><td style=\"padding:0 24px 16px 24px;\">\r\n        <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"border-collapse:collapse;font-size:14px;color:#212121;\">\r\n          <tr>\r\n            <td style=\"padding:8px 10px;background:#f5f5f5;font-weight:bold;width:35%;border-bottom:1px solid #e0e0e0;\">##lang.ticket.creationdate##</td>\r\n            <td style=\"padding:8px 10px;border-bottom:1px solid #e0e0e0;\">##ticket.creationdate##</td>\r\n          </tr>\r\n          <tr>\r\n            <td style=\"padding:8px 10px;background:#f5f5f5;font-weight:bold;border-bottom:1px solid #e0e0e0;\">##lang.ticket.status##</td>\r\n            <td style=\"padding:8px 10px;border-bottom:1px solid #e0e0e0;\">##ticket.status##</td>\r\n          </tr>\r\n          <tr>\r\n            <td style=\"padding:8px 10px;background:#f5f5f5;font-weight:bold;border-bottom:1px solid #e0e0e0;\">##lang.ticket.requesttype##</td>\r\n            <td style=\"padding:8px 10px;border-bottom:1px solid #e0e0e0;\">##ticket.requesttype##</td>\r\n          </tr>\r\n          <tr>\r\n            <td style=\"padding:8px 10px;background:#f5f5f5;font-weight:bold;border-bottom:1px solid #e0e0e0;\">##lang.ticket.priority##</td>\r\n            <td style=\"padding:8px 10px;border-bottom:1px solid #e0e0e0;\">##ticket.priority##</td>\r\n          </tr>\r\n          <tr>\r\n            <td style=\"padding:8px 10px;background:#f5f5f5;font-weight:bold;border-bottom:1px solid #e0e0e0;\">##lang.ticket.urgency##</td>\r\n            <td style=\"padding:8px 10px;border-bottom:1px solid #e0e0e0;\">##ticket.urgency##</td>\r\n          </tr>\r\n          ##IFticket.category##\r\n          <tr>\r\n            <td style=\"padding:8px 10px;background:#f5f5f5;font-weight:bold;border-bottom:1px solid #e0e0e0;\">##lang.ticket.category##</td>\r\n            <td style=\"padding:8px 10px;border-bottom:1px solid #e0e0e0;\">##ticket.category##</td>\r\n          </tr>\r\n          ##ENDIFticket.category##\r\n          ##IFticket.assigntousers##\r\n          <tr>\r\n            <td style=\"padding:8px 10px;background:#f5f5f5;font-weight:bold;border-bottom:1px solid #e0e0e0;\">##lang.ticket.assigntousers##</td>\r\n            <td style=\"padding:8px 10px;border-bottom:1px solid #e0e0e0;\">##ticket.assigntousers##</td>\r\n          </tr>\r\n          ##ENDIFticket.assigntousers##\r\n          ##IFticket.assigntogroups##\r\n          <tr>\r\n            <td style=\"padding:8px 10px;background:#f5f5f5;font-weight:bold;border-bottom:1px solid #e0e0e0;\">##lang.ticket.assigntogroups##</td>\r\n            <td style=\"padding:8px 10px;border-bottom:1px solid #e0e0e0;\">##ticket.assigntogroups##</td>\r\n          </tr>\r\n          ##ENDIFticket.assigntogroups##\r\n        </table>\r\n      </td></tr>\r\n\r\n      <!-- Description -->\r\n      <tr><td style=\"padding:0 24px 8px 24px;\">\r\n        <div style=\"font-size:11px;color:#616161;text-transform:uppercase;letter-spacing:1px;margin-bottom:6px;\">##lang.ticket.description##</div>\r\n        <div style=\"background:#fafafa;border:1px solid #e0e0e0;border-radius:4px;padding:14px 16px;font-size:14px;color:#212121;line-height:1.5;\">\r\n          ##ticket.content##\r\n        </div>\r\n      </td></tr>\r\n\r\n      <!-- Associated items -->\r\n      ##FOREACHitems##\r\n      <tr><td style=\"padding:8px 24px 0 24px;\">\r\n        ##IFticket.itemtype##\r\n        <div style=\"font-size:13px;color:#424242;\">\r\n          <strong>##lang.ticket.item.name##:</strong>\r\n          ##ticket.itemtype## - ##ticket.item.name##\r\n          ##IFticket.item.model## (##lang.ticket.item.model##: ##ticket.item.model##)##ENDIFticket.item.model##\r\n          ##IFticket.item.serial## | ##lang.ticket.item.serial##: ##ticket.item.serial####ENDIFticket.item.serial##\r\n          ##IFticket.item.otherserial## | ##lang.ticket.item.otherserial##: ##ticket.item.otherserial####ENDIFticket.item.otherserial##\r\n        </div>\r\n        ##ENDIFticket.itemtype##\r\n      </td></tr>\r\n      ##ENDFOREACHitems##\r\n\r\n      <!-- Solution (if solved/closed) -->\r\n      ##IFticket.storestatus=5##\r\n      <tr><td style=\"padding:16px 24px;\">\r\n        <div style=\"background:#e8f5e9;border-left:4px solid #2E7D32;border-radius:4px;padding:12px 16px;font-size:14px;\">\r\n          <div style=\"font-weight:bold;color:#1B5E20;margin-bottom:6px;\">##lang.ticket.solvedate##: ##ticket.solvedate##</div>\r\n          <div><strong>##lang.ticket.solution.type##:</strong> ##ticket.solution.type##</div>\r\n          <div style=\"margin-top:6px;\"><strong>##lang.ticket.solution.description##:</strong> ##ticket.solution.description##</div>\r\n        </div>\r\n      </td></tr>\r\n      ##ENDIFticket.storestatus##\r\n\r\n      ##IFticket.storestatus=6##\r\n      <tr><td style=\"padding:16px 24px;\">\r\n        <div style=\"background:#e8f5e9;border-left:4px solid #2E7D32;border-radius:4px;padding:12px 16px;font-size:14px;\">\r\n          <div style=\"font-weight:bold;color:#1B5E20;margin-bottom:6px;\">##lang.ticket.solvedate##: ##ticket.solvedate##</div>\r\n          <div><strong>##lang.ticket.solution.type##:</strong> ##ticket.solution.type##</div>\r\n          <div style=\"margin-top:6px;\"><strong>##lang.ticket.solution.description##:</strong> ##ticket.solution.description##</div>\r\n        </div>\r\n      </td></tr>\r\n      ##ENDIFticket.storestatus##\r\n\r\n      <!-- Timeline (followups) -->\r\n      ##FOREACHtimelineitems##\r\n      <tr><td style=\"padding:6px 24px;\">\r\n        <div style=\"background:#fafafa;border:1px solid #e0e0e0;border-radius:4px;padding:10px 14px;font-size:13px;color:#212121;\">\r\n          <div style=\"font-size:11px;color:#616161;margin-bottom:4px;\">\r\n            [##timelineitems.date##] &mdash; ##timelineitems.author## &mdash; ##timelineitems.typename##\r\n          </div>\r\n          <div>##timelineitems.description##</div>\r\n        </div>\r\n      </td></tr>\r\n      ##ENDFOREACHtimelineitems##\r\n\r\n      <!-- Counters -->\r\n      <tr><td style=\"padding:12px 24px;font-size:12px;color:#616161;\">\r\n        ##lang.ticket.numberoffollowups##: ##ticket.numberoffollowups## &nbsp;|&nbsp; ##lang.ticket.numberoftasks##: ##ticket.numberoftasks##\r\n      </td></tr>\r\n\r\n      <!-- How to reply by email -->\r\n      <tr><td style=\"padding:0 24px 16px 24px;\">\r\n        <div style=\"border-top:1px solid #e0e0e0;padding-top:14px;font-size:12px;color:#616161;line-height:1.5;\">\r\n          <strong style=\"color:#1B5E20;\">&iquest;C&oacute;mo crear o responder un caso por correo?</strong><br>\r\n          Env&iacute;e su correo a <a href=\"mailto:tisantacruz48@gmail.com\" style=\"color:#2E7D32;\">tisantacruz48@gmail.com</a> incluyendo:<br>\r\n          &bull; <strong>Asunto claro</strong> con el problema (ej. \"No puedo acceder al sistema\").<br>\r\n          &bull; <strong>Su nombre completo</strong> y el &aacute;rea o sede.<br>\r\n          &bull; <strong>Descripci&oacute;n detallada</strong> del inconveniente.<br>\r\n          &bull; Adjunte capturas o evidencias si aplica.<br>\r\n          Para responder a este caso, escriba <em>arriba</em> de la l&iacute;nea: <code>=-=-=-= Para responder por correo electr&oacute;nico, escriba arriba de esta l&iacute;nea =-=-=-=</code>\r\n        </div>\r\n      </td></tr>\r\n\r\n      <!-- Footer -->\r\n      <tr><td style=\"background:#1B5E20;padding:14px 24px;color:#ffffff;font-size:12px;text-align:center;\">\r\n        Mesa de Ayuda TI &mdash; Grupo Empresarial Santacruz<br>\r\n        <span style=\"font-size:11px;opacity:.85;\">Generado autom&aacute;ticamente por GLPI</span>\r\n      </td></tr>\r\n\r\n    </table>\r\n  </td></tr>\r\n</table>'),(5,12,'','##contract.action##  ##contract.entity##','##lang.contract.entity## : ##contract.entity##\n\n##FOREACHcontracts##\n##lang.contract.name## : ##contract.name##\n